    # ─────────────────── BANCO DE DADOS ───────────────────
    def configurar_banco(self):
        self.cursor.executescript("""
            CREATE TABLE IF NOT EXISTS produtos (
                codigo TEXT PRIMARY KEY,
                nome TEXT,
                preco REAL,
                estoque INTEGER,
                custo REAL DEFAULT 0,
                estoque_min INTEGER DEFAULT 5,
                preco_manual INTEGER DEFAULT 0,
                preco_promocional REAL DEFAULT 0,
                data_cadastro TEXT,
                data_alteracao TEXT
            );
            CREATE TABLE IF NOT EXISTS clientes (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                nome TEXT, divida REAL DEFAULT 0,
                telefone TEXT, obs TEXT, cpf TEXT,
                limite_fiado REAL DEFAULT 0
            );
            CREATE TABLE IF NOT EXISTS vendas (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                data DATETIME, total REAL, lucro REAL,
                metodo TEXT, cliente_fiado TEXT
            );
            CREATE TABLE IF NOT EXISTS itens_venda (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                id_venda INTEGER, produto TEXT, qtd INTEGER, preco_unit REAL
            );
            CREATE TABLE IF NOT EXISTS caixa (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                data DATETIME, tipo TEXT, valor REAL, descricao TEXT
            );
            CREATE TABLE IF NOT EXISTS log_exclusoes (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                data DATETIME, tipo TEXT, descricao TEXT
            );

            CREATE TABLE IF NOT EXISTS usuarios (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                usuario TEXT UNIQUE,
                senha TEXT,
                nivel TEXT
            );

            CREATE TABLE IF NOT EXISTS movimentos_fiado (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                cliente TEXT,
                data DATETIME,
                tipo TEXT,
                valor REAL,
                observacao TEXT
            );
            CREATE TABLE IF NOT EXISTS configuracoes (
                chave TEXT PRIMARY KEY,
                valor TEXT
            );
        """)
        # Migrações seguras para banco existente
        for col, tipo in [("limite_fiado","REAL DEFAULT 0"),("obs","TEXT"),
                          ("telefone","TEXT"),("cpf","TEXT")]:
            try: self.cursor.execute(f"ALTER TABLE clientes ADD COLUMN {col} {tipo}")
            except: pass
        try: self.cursor.execute("ALTER TABLE vendas ADD COLUMN desconto REAL DEFAULT 0")
        except: pass

        try: self.cursor.execute("ALTER TABLE produtos ADD COLUMN preco_manual INTEGER DEFAULT 0")
        except: pass
        try: self.cursor.execute("ALTER TABLE produtos ADD COLUMN preco_promocional REAL DEFAULT 0")
        except: pass
        try: self.cursor.execute("ALTER TABLE produtos ADD COLUMN data_cadastro TEXT")
        except: pass
        try: self.cursor.execute("ALTER TABLE produtos ADD COLUMN data_alteracao TEXT")
        except: pass

        # Garante histórico de datas para produtos novos e antigos.
        agora = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        self.cursor.execute("UPDATE produtos SET data_cadastro=COALESCE(data_cadastro, ?), data_alteracao=COALESCE(data_alteracao, ?) WHERE data_cadastro IS NULL OR data_alteracao IS NULL", (agora, agora))
        self.cursor.executescript("""
            CREATE TRIGGER IF NOT EXISTS trg_produtos_data_insert
            AFTER INSERT ON produtos
            FOR EACH ROW
            WHEN NEW.data_cadastro IS NULL OR NEW.data_alteracao IS NULL
            BEGIN
                UPDATE produtos
                SET data_cadastro = COALESCE(NEW.data_cadastro, datetime('now','localtime')),
                    data_alteracao = COALESCE(NEW.data_alteracao, datetime('now','localtime'))
                WHERE codigo = NEW.codigo;
            END;

            CREATE TRIGGER IF NOT EXISTS trg_produtos_data_update
            AFTER UPDATE ON produtos
            FOR EACH ROW
            WHEN OLD.nome IS NOT NEW.nome
              OR OLD.preco IS NOT NEW.preco
              OR OLD.estoque IS NOT NEW.estoque
              OR OLD.custo IS NOT NEW.custo
              OR OLD.estoque_min IS NOT NEW.estoque_min
              OR OLD.preco_manual IS NOT NEW.preco_manual
              OR OLD.preco_promocional IS NOT NEW.preco_promocional
            BEGIN
                UPDATE produtos
                SET data_alteracao = datetime('now','localtime')
                WHERE codigo = NEW.codigo;
            END;
        """)

        self.cursor.execute("SELECT * FROM usuarios WHERE usuario='admin'")
        admin = self.cursor.fetchone()

        if not admin:
            senha = hashlib.sha256("1234".encode()).hexdigest()
            self.cursor.execute(
                "INSERT INTO usuarios (usuario, senha, nivel) VALUES (?,?,?)",
                ("admin", senha, "ADMIN")
            )

        self.conn.commit()

