    def _preparar_assets_visuais(self):
        """Cria os arquivos de logo/QR a partir das imagens embutidas no próprio .py."""
        try:
            pasta = os.path.join(PASTA_BASE, "assets_teita")
            os.makedirs(pasta, exist_ok=True)
            self.logo_path = os.path.join(pasta, "logo_mercadinho_teita.png")
            self.pix_qr_path = os.path.join(pasta, "pix_qr_teita.png")
            if not os.path.exists(self.logo_path):
                with open(self.logo_path, "wb") as f:
                    f.write(base64.b64decode(LOGO_TEITA_B64))
            if not os.path.exists(self.pix_qr_path):
                with open(self.pix_qr_path, "wb") as f:
                    f.write(base64.b64decode(PIX_QR_B64))
        except Exception:
            self.logo_path = ""
            self.pix_qr_path = ""

    def _carregar_configuracoes_sistema(self):
        """Carrega nome da loja, impressora e imagens configuradas no banco."""
        global NOME_LOJA, NOME_IMPRESSORA_CUPOM
        try:
            nome = self._config_get("nome_loja", NOME_LOJA).strip() or NOME_LOJA
            impressora = self._config_get("impressora_cupom", NOME_IMPRESSORA_CUPOM).strip() or NOME_IMPRESSORA_CUPOM
            NOME_LOJA = nome
            NOME_IMPRESSORA_CUPOM = impressora
            logo_cfg = self._config_get("logo_path", "").strip()
            pix_cfg = self._config_get("pix_qr_path", "").strip()
            if logo_cfg and os.path.exists(logo_cfg):
                self.logo_path = logo_cfg
            if pix_cfg and os.path.exists(pix_cfg):
                self.pix_qr_path = pix_cfg
        except Exception:
            pass

    def _nome_loja_atual(self):
        return self._config_get("nome_loja", NOME_LOJA).strip() or NOME_LOJA

    def _impressora_atual(self):
        return self._config_get("impressora_cupom", NOME_IMPRESSORA_CUPOM).strip() or NOME_IMPRESSORA_CUPOM

    def _logo_atual(self):
        caminho = self._config_get("logo_path", "").strip()
        if caminho and os.path.exists(caminho):
            return caminho
        return getattr(self, "logo_path", "")

    def _pix_qr_atual(self):
        caminho = self._config_get("pix_qr_path", "").strip()
        if caminho and os.path.exists(caminho):
            return caminho
        return getattr(self, "pix_qr_path", "")

    def _listar_impressoras_windows(self):
        try:
            import win32print
            return sorted([p[2] for p in win32print.EnumPrinters(2)])
        except Exception:
            return []

    def _exibir_qr_pix_cliente(self):
        """Mostra o QR Code Pix cadastrado para o cliente visualizar na tela."""
        caminho = self._pix_qr_atual()
        if not caminho or not os.path.exists(caminho):
            messagebox.showwarning("QR Code Pix", "Nenhum QR Code Pix foi configurado ainda.")
            return
        top = tk.Toplevel(self.root)
        top.title("QR Code Pix para pagamento")
        self.centralizar_janela(top, 430, 520)
        top.configure(bg="white")
        top.transient(self.root)
        tk.Label(top, text="Aponte a câmera para pagar no Pix", bg="white", fg="#111827", font=("Segoe UI", 16, "bold")).pack(pady=(18, 8))
        try:
            img = tk.PhotoImage(file=caminho)
            fator = max(1, int(max(img.width() / 330, img.height() / 330)))
            self._pix_img_janela = img.subsample(fator, fator)
            tk.Label(top, image=self._pix_img_janela, bg="white").pack(pady=10)
        except Exception:
            tk.Label(top, text=f"Arquivo selecionado:\n{caminho}", bg="white", fg="#111827", wraplength=360).pack(pady=40)
        tk.Button(top, text="FECHAR", bg=COR_AZUL, fg="white", font=("Segoe UI", 11, "bold"), bd=0, command=top.destroy).pack(fill="x", padx=40, pady=18, ipady=8)
        top.focus_force()

    def _perguntar_exibir_qr_pix(self):
        try:
            if messagebox.askyesno("PIX", "Deseja exibir o QR Code Pix cadastrado para o cliente?"):
                self._exibir_qr_pix_cliente()
        except Exception:
            pass

    def _obter_indicadores_dashboard(self, data_ini=None, data_fim=None):
        """Retorna os indicadores do Dashboard filtrando vendas por período.
        As datas devem estar em formato AAAA-MM-DD. Quando não informado, usa o dia atual.
        """
        hoje = datetime.now().strftime("%Y-%m-%d")
        data_ini = (data_ini or hoje).strip()
        data_fim = (data_fim or data_ini).strip()

        # Vendas e lucro do período selecionado.
        self.cursor.execute(
            """
            SELECT COALESCE(SUM(total),0), COALESCE(SUM(lucro),0)
            FROM vendas
            WHERE date(data) BETWEEN ? AND ?
            """,
            (data_ini, data_fim)
        )
        total, lucro = self.cursor.fetchone() or (0, 0)

        # Valor vendido no FIADO dentro do período selecionado.
        self.cursor.execute(
            """
            SELECT COALESCE(SUM(total),0)
            FROM vendas
            WHERE date(data) BETWEEN ? AND ?
              AND UPPER(COALESCE(metodo,'')) LIKE '%FIADO%'
            """,
            (data_ini, data_fim)
        )
        fiado_periodo = self.cursor.fetchone()[0] or 0

        # Indicadores gerais, independentes do período.
        self.cursor.execute("SELECT COUNT(*) FROM produtos WHERE estoque <= estoque_min")
        baixo = self.cursor.fetchone()[0]
        self.cursor.execute("SELECT COUNT(*) FROM clientes WHERE divida > 0")
        dev = self.cursor.fetchone()[0]
        self.cursor.execute("SELECT COALESCE(SUM(divida),0) FROM clientes WHERE divida > 0")
        fiado_aberto = self.cursor.fetchone()[0] or 0

        return {
            "vendas": f"R$ {float(total or 0):.2f}".replace('.', ','),
            "lucro": f"R$ {float(lucro or 0):.2f}".replace('.', ','),
            "fiado": f"R$ {float(fiado_periodo or 0):.2f}".replace('.', ','),
            "baixo": f"{baixo} itens",
            "devedores": str(dev),
            "fiado_aberto": f"R$ {float(fiado_aberto or 0):.2f}".replace('.', ','),
            "data_ini": data_ini,
            "data_fim": data_fim,
        }

