    def _criar_card(self, parent, titulo, valor, cor):
        card = tk.Frame(parent, bg=COR_CARD, highlightthickness=1, highlightbackground="#3A4353")
        card.pack(side="left", fill="x", expand=True, padx=5)
        tk.Frame(card, bg=cor, height=4).pack(fill="x")
        tk.Label(card, text=titulo, bg=COR_CARD, fg=COR_TEXTO_SUAVE, font=("Segoe UI", 9, "bold")).pack(anchor="w", padx=12, pady=(8, 0))
        lbl = tk.Label(card, text=valor, bg=COR_CARD, fg="white", font=("Segoe UI", 16, "bold"))
        lbl.pack(anchor="w", padx=12, pady=(0, 10))
        return lbl

    def _atualizar_cards_dashboard(self):
        try:
            data_ini = self.dashboard_data_ini.get().strip() if hasattr(self, "dashboard_data_ini") else None
            data_fim = self.dashboard_data_fim.get().strip() if hasattr(self, "dashboard_data_fim") else None
            dados = self._obter_indicadores_dashboard(data_ini, data_fim)
            if hasattr(self, "card_vendas"):
                self.card_vendas.config(text=dados["vendas"])
            if hasattr(self, "card_lucro"):
                self.card_lucro.config(text=dados["lucro"])
            if hasattr(self, "card_fiado"):
                self.card_fiado.config(text=dados["fiado"])
            if hasattr(self, "card_baixo"):
                self.card_baixo.config(text=dados["baixo"])
            if hasattr(self, "card_devedores"):
                self.card_devedores.config(text=dados["devedores"])
            if hasattr(self, "card_fiado_aberto"):
                self.card_fiado_aberto.config(text=dados["fiado_aberto"])
        except Exception:
            pass

    def adicionar_produto_animado(self, event=None):
        self.adicionar_produto(event)
        try:
            self.entry_codigo.config(highlightbackground="#00E676")
            self.root.after(180, lambda: self.entry_codigo.config(highlightbackground=COR_VERDE))
        except Exception:
            pass
        self.atualizar_resumo_financeiro_pdv()
        self.refocar_bipador_se_tela_venda(180)

    def atualizar_resumo_financeiro_pdv(self):
        try:
            itens = sum(int(i.get("qtd", 0)) for i in self.carrinho)
            txt = (
                f"Subtotal: R$ {self.total_bruto:.2f}\n"
                f"Desconto: R$ {self.valor_desconto:.2f}\n"
                f"Itens: {itens}"
            ).replace('.', ',')
            self.lbl_resumo_fin.config(text=txt)
            self._atualizar_cards_dashboard()
        except Exception:
            pass

    def abrir_dashboard(self):
        top = tk.Toplevel(self.root)
        top.title("Dashboard - Mercadinho do Teita")
        self.centralizar_janela(top, 1180, 640)
        top.configure(bg=COR_FUNDO)
        top.transient(self.root)

        tk.Label(top, text="Dashboard do Mercadinho", bg=COR_FUNDO, fg="white", font=("Segoe UI", 22, "bold")).pack(anchor="w", padx=24, pady=(20, 6))

        # Filtro por período.
        hoje = datetime.now().strftime("%Y-%m-%d")
        filtro = tk.Frame(top, bg=COR_FUNDO)
        filtro.pack(fill="x", padx=24, pady=(0, 12))
        tk.Label(filtro, text="Data inicial:", bg=COR_FUNDO, fg=COR_TEXTO_SUAVE, font=("Segoe UI", 10, "bold")).pack(side="left")
        self.dashboard_data_ini = tk.Entry(filtro, width=12, font=("Segoe UI", 10))
        self.dashboard_data_ini.insert(0, hoje)
        self.dashboard_data_ini.pack(side="left", padx=(6, 14))
        tk.Label(filtro, text="Data final:", bg=COR_FUNDO, fg=COR_TEXTO_SUAVE, font=("Segoe UI", 10, "bold")).pack(side="left")
        self.dashboard_data_fim = tk.Entry(filtro, width=12, font=("Segoe UI", 10))
        self.dashboard_data_fim.insert(0, hoje)
        self.dashboard_data_fim.pack(side="left", padx=(6, 14))
        tk.Label(filtro, text="Formato: AAAA-MM-DD", bg=COR_FUNDO, fg="#94A3B8", font=("Segoe UI", 9)).pack(side="left", padx=(0, 12))

        cards = tk.Frame(top, bg=COR_FUNDO)
        cards.pack(fill="x", padx=18)
        dados = self._obter_indicadores_dashboard(hoje, hoje)
        self.card_vendas = self._criar_card(cards, "Vendas no período", dados["vendas"], COR_AZUL)
        self.card_lucro = self._criar_card(cards, "Lucro no período", dados["lucro"], COR_VERDE)
        self.card_fiado = self._criar_card(cards, "Fiado no período", dados["fiado"], "#8B5CF6")
        self.card_baixo = self._criar_card(cards, "Estoque baixo", dados["baixo"], "#F39C12")
        self.card_devedores = self._criar_card(cards, "Clientes devendo", dados["devedores"], COR_VERMELHO)
        self.card_fiado_aberto = self._criar_card(cards, "Fiado em aberto", dados["fiado_aberto"], "#06B6D4")

        box = tk.LabelFrame(top, text="Vendas do período", bg=COR_FUNDO, fg="white", font=("Segoe UI", 11, "bold"))
        box.pack(fill="both", expand=True, padx=24, pady=20)

        frame_tree = tk.Frame(box, bg=COR_FUNDO)
        frame_tree.pack(fill="both", expand=True, padx=10, pady=10)
        tree_dash = ttk.Treeview(frame_tree, columns=("Data", "Total", "Método", "Cliente"), show="headings")
        for col, w in [("Data", 160), ("Total", 110), ("Método", 180), ("Cliente", 360)]:
            tree_dash.heading(col, text=col.upper())
            tree_dash.column(col, width=w)
        scroll_y = ttk.Scrollbar(frame_tree, orient="vertical", command=tree_dash.yview)
        scroll_x = ttk.Scrollbar(frame_tree, orient="horizontal", command=tree_dash.xview)
        tree_dash.configure(yscrollcommand=scroll_y.set, xscrollcommand=scroll_x.set)
        tree_dash.grid(row=0, column=0, sticky="nsew")
        scroll_y.grid(row=0, column=1, sticky="ns")
        scroll_x.grid(row=1, column=0, sticky="ew")
        frame_tree.grid_rowconfigure(0, weight=1)
        frame_tree.grid_columnconfigure(0, weight=1)

        def carregar_dashboard(event=None):
            data_ini = self.dashboard_data_ini.get().strip() or hoje
            data_fim = self.dashboard_data_fim.get().strip() or data_ini
            try:
                # Valida formato das datas antes de consultar.
                datetime.strptime(data_ini, "%Y-%m-%d")
                datetime.strptime(data_fim, "%Y-%m-%d")
            except Exception:
                messagebox.showwarning("Data inválida", "Informe as datas no formato AAAA-MM-DD.\nExemplo: 2026-05-28", parent=top)
                return

            dados_atualizados = self._obter_indicadores_dashboard(data_ini, data_fim)
            self.card_vendas.config(text=dados_atualizados["vendas"])
            self.card_lucro.config(text=dados_atualizados["lucro"])
            self.card_fiado.config(text=dados_atualizados["fiado"])
            self.card_baixo.config(text=dados_atualizados["baixo"])
            self.card_devedores.config(text=dados_atualizados["devedores"])
            self.card_fiado_aberto.config(text=dados_atualizados["fiado_aberto"])

            tree_dash.delete(*tree_dash.get_children())
            try:
                self.cursor.execute(
                    """
                    SELECT data,total,metodo,COALESCE(cliente_fiado,'Consumidor Final')
                    FROM vendas
                    WHERE date(data) BETWEEN ? AND ?
                    ORDER BY id DESC
                    LIMIT 200
                    """,
                    (data_ini, data_fim)
                )
                for data, total, metodo, cliente in self.cursor.fetchall():
                    tree_dash.insert("", "end", values=(data, f"R$ {float(total or 0):.2f}".replace('.', ','), metodo, cliente))
            except Exception as erro:
                messagebox.showerror("Erro", f"Não foi possível carregar as vendas do período:\n{erro}", parent=top)

        tk.Button(filtro, text="APLICAR FILTRO", bg=COR_AZUL, fg="white", font=("Segoe UI", 9, "bold"), bd=0, command=carregar_dashboard).pack(side="left", padx=6, ipady=3)

        def hoje_dashboard():
            self.dashboard_data_ini.delete(0, "end")
            self.dashboard_data_ini.insert(0, hoje)
            self.dashboard_data_fim.delete(0, "end")
            self.dashboard_data_fim.insert(0, hoje)
            carregar_dashboard()

        tk.Button(filtro, text="HOJE", bg="#475569", fg="white", font=("Segoe UI", 9, "bold"), bd=0, command=hoje_dashboard).pack(side="left", padx=4, ipady=3)
        self.dashboard_data_ini.bind("<Return>", carregar_dashboard)
        self.dashboard_data_fim.bind("<Return>", carregar_dashboard)
        top.bind("<Escape>", lambda e: top.destroy())
        carregar_dashboard()

    def abrir_configuracoes_visual(self):
        top = tk.Toplevel(self.root)
        top.title("Configurações do Sistema")
        self.centralizar_janela(top, 900, 760)
        top.configure(bg=COR_FUNDO)
        top.transient(self.root)

        tk.Label(top, text="Configurações", bg=COR_FUNDO, fg="white", font=("Segoe UI", 22, "bold")).pack(anchor="w", padx=24, pady=(18, 6))
        tk.Label(top, text="Altere os dados principais do PDV. As configurações ficam salvas no banco.", bg=COR_FUNDO, fg=COR_TEXTO_SUAVE, font=("Segoe UI", 10)).pack(anchor="w", padx=24, pady=(0, 14))

        painel = tk.Frame(top, bg=COR_CARD, highlightthickness=1, highlightbackground="#3A4353")
        painel.pack(fill="both", expand=True, padx=24, pady=10)

        def linha(rotulo):
            f = tk.Frame(painel, bg=COR_CARD)
            f.pack(fill="x", padx=18, pady=8)
            tk.Label(f, text=rotulo, bg=COR_CARD, fg="white", font=("Segoe UI", 10, "bold"), width=22, anchor="w").pack(side="left")
            return f

        f_nome = linha("Nome do mercadinho")
        ent_nome = tk.Entry(f_nome, font=("Segoe UI", 11))
        ent_nome.insert(0, self._nome_loja_atual())
        ent_nome.pack(side="left", fill="x", expand=True, ipady=4)

        f_imp = linha("Impressora do cupom")
        impressoras = self._listar_impressoras_windows()
        var_imp = tk.StringVar(value=self._impressora_atual())
        if impressoras:
            cb_imp = ttk.Combobox(f_imp, textvariable=var_imp, values=impressoras, state="readonly", font=("Segoe UI", 10))
            cb_imp.pack(side="left", fill="x", expand=True, ipady=3)
        else:
            ent_imp = tk.Entry(f_imp, textvariable=var_imp, font=("Segoe UI", 11))
            ent_imp.pack(side="left", fill="x", expand=True, ipady=4)

        f_logo = linha("Logo do mercadinho")
        var_logo = tk.StringVar(value=self._logo_atual())
        ent_logo = tk.Entry(f_logo, textvariable=var_logo, font=("Segoe UI", 9))
        ent_logo.pack(side="left", fill="x", expand=True, ipady=4)
        def escolher_logo():
            arq = filedialog.askopenfilename(title="Selecionar logo", filetypes=[("Imagens PNG/GIF", "*.png *.gif"), ("Todas", "*.*")])
            if arq:
                var_logo.set(arq)
        tk.Button(f_logo, text="Selecionar", bg=COR_AZUL, fg="white", bd=0, command=escolher_logo).pack(side="left", padx=(8,0), ipadx=10, ipady=4)

        f_pix = linha("QR Code Pix")
        var_pix = tk.StringVar(value=self._pix_qr_atual())
        ent_pix = tk.Entry(f_pix, textvariable=var_pix, font=("Segoe UI", 9))
        ent_pix.pack(side="left", fill="x", expand=True, ipady=4)
        def escolher_pix():
            arq = filedialog.askopenfilename(title="Selecionar QR Code Pix", filetypes=[("Imagens PNG/GIF", "*.png *.gif"), ("Todas", "*.*")])
            if arq:
                var_pix.set(arq)
        tk.Button(f_pix, text="Selecionar", bg=COR_AZUL, fg="white", bd=0, command=escolher_pix).pack(side="left", padx=(8,0), ipadx=10, ipady=4)

        f_cnpj = linha("CNPJ DF-e")
        var_dfe_cnpj = tk.StringVar(value=self._config_get("dfe_cnpj", "21818077000143"))
        ent_dfe_cnpj = tk.Entry(f_cnpj, textvariable=var_dfe_cnpj, font=("Segoe UI", 11))
        ent_dfe_cnpj.pack(side="left", fill="x", expand=True, ipady=4)

        f_uf = linha("UF DF-e")
        var_dfe_uf = tk.StringVar(value=self._config_get("dfe_uf", "CE"))
        ent_dfe_uf = tk.Entry(f_uf, textvariable=var_dfe_uf, font=("Segoe UI", 11), width=8)
        ent_dfe_uf.pack(side="left", anchor="w", ipady=4)

        f_cert = linha("Certificado A1 DF-e")
        var_dfe_cert = tk.StringVar(value=self._config_get("dfe_certificado", ""))
        ent_dfe_cert = tk.Entry(f_cert, textvariable=var_dfe_cert, font=("Segoe UI", 9))
        ent_dfe_cert.pack(side="left", fill="x", expand=True, ipady=4)
        def escolher_dfe_cert():
            arq = filedialog.askopenfilename(title="Selecionar certificado A1", filetypes=[("Certificado A1", "*.pfx *.p12"), ("Todos", "*.*")])
            if arq:
                var_dfe_cert.set(arq)
        tk.Button(f_cert, text="Selecionar", bg=COR_AZUL, fg="white", bd=0, command=escolher_dfe_cert).pack(side="left", padx=(8,0), ipadx=10, ipady=4)

        f_senha = linha("Senha certificado")
        var_dfe_senha = tk.StringVar(value=self._config_get("dfe_senha", ""))
        ent_dfe_senha = tk.Entry(f_senha, textvariable=var_dfe_senha, font=("Segoe UI", 11), show="*")
        ent_dfe_senha.pack(side="left", fill="x", expand=True, ipady=4)

        preview = tk.Frame(painel, bg=COR_CARD)
        preview.pack(fill="x", padx=18, pady=(10, 4))
        tk.Label(preview, text="Observação: para visualizar a nova logo no topo, salve e reinicie o sistema.", bg=COR_CARD, fg=COR_TEXTO_SUAVE, font=("Segoe UI", 9)).pack(anchor="w")
        tk.Label(preview, text="No pagamento PIX, o sistema perguntará se deseja mostrar o QR Code ao cliente.", bg=COR_CARD, fg=COR_TEXTO_SUAVE, font=("Segoe UI", 9)).pack(anchor="w", pady=(3,0))
        tk.Label(preview, text="DF-e: informe CNPJ, UF, certificado A1 e senha uma vez; a tela de baixar XMLs já carrega esses dados.", bg=COR_CARD, fg=COR_TEXTO_SUAVE, font=("Segoe UI", 9)).pack(anchor="w", pady=(3,0))

        botoes = tk.Frame(top, bg=COR_FUNDO)
        botoes.pack(fill="x", padx=24, pady=(0, 18))

        def salvar():
            global NOME_LOJA, NOME_IMPRESSORA_CUPOM
            nome = ent_nome.get().strip() or "Mercadinho do Teita"
            impressora = var_imp.get().strip() or NOME_IMPRESSORA_CUPOM
            logo = var_logo.get().strip()
            pix = var_pix.get().strip()
            self._config_set("nome_loja", nome)
            self._config_set("impressora_cupom", impressora)
            self._config_set("logo_path", logo)
            self._config_set("pix_qr_path", pix)
            self._config_set("dfe_cnpj", re.sub(r"\D", "", var_dfe_cnpj.get()))
            self._config_set("dfe_uf", var_dfe_uf.get().strip().upper())
            self._config_set("dfe_certificado", var_dfe_cert.get().strip())
            self._config_set("dfe_senha", var_dfe_senha.get())
            NOME_LOJA = nome
            NOME_IMPRESSORA_CUPOM = impressora
            if logo and os.path.exists(logo):
                self.logo_path = logo
            if pix and os.path.exists(pix):
                self.pix_qr_path = pix
            try:
                self.root.title(f"{nome} - PDV Profissional")
            except Exception:
                pass
            messagebox.showinfo("Configurações", "Configurações salvas com sucesso.\nPara atualizar a logo do topo, reinicie o sistema.")
            top.destroy()

        tk.Button(botoes, text="SALVAR CONFIGURAÇÕES", bg=COR_VERDE, fg="white", font=("Segoe UI", 11, "bold"), bd=0, command=salvar).pack(side="right", ipadx=14, ipady=8, padx=6)
        tk.Button(botoes, text="FECHAR", bg="#4B5563", fg="white", font=("Segoe UI", 11, "bold"), bd=0, command=top.destroy).pack(side="right", ipadx=14, ipady=8, padx=6)

